window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2001>1","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Which of the following correctly express 48 as a product of prime numbers","images":[],"options":{"A":"3 x 4 x4","B":"2 x 3 x 8","C":"2 x 2 x 3 x 4","D":"2 x 2 x 2 x 2 x 3"},"answer":"D","explanation":"A prime number is any number that has itself and one as the only two factors.  Using Division method,  2482  2  2  3  24  12  6  3  1  Therefore, 48 = 2 x 2 x 2 x 2 x 3  48 = 2 x 2 x 2 x 2 x 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>2","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Evaluate (20three)2 - (11three)2 in the base three","images":[],"options":{"A":"101","B":"121","C":"202","D":"2020"},"answer":"C","explanation":"(203)2 - (113)2  STEP 1 - Convert to base ten, for easy computation  203 to base 10 \u21d2 2 x 31 + 0 x 30 = 6  113 to base 10 \u21d2 1 \u00d7 31 + 1 \u00d7 30 = 4    STEP 2 - Perform Operations  (203)2 - (113)2    In base 10,  (6)2 - (4)2 = 36 - 16 = 20    STEP 3 - Convert 20 back to base 3  Using long division method,  3203  3  6 rem 2 \u2191  2 rem 0\u2191  0 rem 2 \u2191  2023","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>3","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Evaluate log105 + log1020","images":[],"options":{"A":"2","B":"3","C":"4","D":"5"},"answer":"A","explanation":"log105 + log1020  following the rules of logarithms  Log10A + Log10B = Log10AB  Therefore,  Log105 + Log1020 = Log10(5 \u00d7 20) = Log10100  Log10100 = Log10102  Log10102 = 2 \u00d7 Log1010 = 2 \u00d7 1 = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>4","subject":"Mathematics","year":"2001","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"In a class of 80 student study economics or geography or both. if 65 student study economics and 50 study geography, how may study both","images":[],"options":{"A":"15","B":"30","C":"35","D":"45"},"answer":"C","explanation":"Total number of students in a class \u2192 80  Students who study Economics \u2192 65  Students who study Geography \u2192 50  Let E represents Economics  Let G represent Geography  Therefore, n(E \u222aG) = 80 \u2192 Number of students studying both Economics and Geography   n(E) = 65  n(G) = 50  How many study both subjects? \u2192 n(E \u2229 G)    From the rules of sets   n(E \u222aG) = n(E) + n(G) - n(E \u222aG)  n(E \u2229 G) = 65 + 50 - 80  n(E \u2229 G) = 115 - 80  n(E \u2229 G) = 35","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>5","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"If N varies directly as M and N  = 8 ; when M  = 20; find M when N = 7","images":[],"options":{"A":"13","B":"15","C":"17 1/2","D":"18 1/2"},"answer":"C","explanation":"N varies directly as M  N \u03b1 M  N = kM, k = constant  when N is 8, M = 20  substitute for N and M to find K  8 = K \u00d7 20  8 = 20K  dividing both sides by 20  K=820=25  Find M, when N = 7  substituting  7=25M  multiplyingbothsidesby52  7\u00d752=25M\u00d762  Therefore,M=352=1712","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>6","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBERS IN STANDARD FORM-SCIENTIFIC NOTATION","question":"Express 0.0462 in a standard form","images":[],"options":{"A":"0.462 \u00d7 10-1","B":"0.462 \u00d7 10-2","C":"4.62\u00d7 10-1","D":"4.62\u00d7 10-2"},"answer":"D","explanation":"0.0462 in standard form  Taking the decimal point two places to the right   0.0462 = 4.62 \u00d7 10-2","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2001>7","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"in a bag of oranges, the ratio of the goods ones to the bad ones is 5:4. if the number of bad oranges in the bag is 36, how many oranges are there altogether","images":[],"options":{"A":"81","B":"72","C":"54","D":"45"},"answer":"A","explanation":"The ratio of good orange to bad orange is 5:4  Good : Bad is 5 : 4  If bad = 36, which is 4/9 of total oranges   Note: Sum of ratio = 5 + 4 = 9  Taking total oranges as X  49\u00d7X=36  Multiplying both sides by 9/4 we have,  49\u00d7X\u00d794=36\u00d794  X = 81  Total Oranges is 81","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2001>8","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGE ERROR","question":"A boy estimated his transport fare for a journey as \u20a6190 instead of  \u20a6200. find the percentage error in his estimate","images":[],"options":{"A":"95%","B":"47.5%","C":"5.26%","D":"5%"},"answer":"D","explanation":"percentageerror=erroractualx100  Estimated fare  = \u20a6190, Actual fare  \u20a6200  Error = Actual fare - estimated fare    = 200 - 190 = \u20a610  Percentageerror=10200x100   = 5%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>9","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Evaluate 5 2/5 x (2/3) \u00f7 (1 1/2)-1","images":[],"options":{"A":"825","B":"1225","C":"335","D":"418"},"answer":"C","explanation":"525x(23)2\u00f7(112)-1  Following BODMAS rule   525x(49)\u00f7(32)-1  525x(49)\u00f7(23)  converting to improper fraction  275\u00d749\u00d732  185=335","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>10","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"the nth term of a sequence is 22n-1. which term of the sequence is 29?","images":[],"options":{"A":"3rd","B":"4th","C":"5th","D":"6th"},"answer":"C","explanation":"The nth term of a sequence is given as 22n - 1,  29 = 22n - 1  equating both powers  2n - 1 = 9  adding one to both sides  2n - 1 + 1 = 9 + 1  2n = 10  dividing both sides by 2  2n2=102,n=5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>11","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"Evaluate12+34of25\u00f7135","images":[],"options":{"A":"1516","B":"1116","C":"4950","D":"315"},"answer":"B","explanation":"12+34of25\u00f7135  Following the rule of BODMAS  12+(34of25)\u00f7135  12+(620)\u00f7135  converting to improper fraction  12+(620)\u00f785  12+(620\u00f785)  12+(620x58)  12+(34x14)  12+316  8+316=1116","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>12","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"A man is four times as old as his son . the difference between their ages is 36 years. find the sum of their ages","images":[],"options":{"A":"45 years","B":"48 years","C":"60 years","D":"120 years"},"answer":"C","explanation":"Take Man's age as X  Take Son's age as Y  A man is four times his son's age : x = 4y  Difference between their ages is : x - y = 36  substituting x for 4y we have  4y - y = 36  3y = 36  dividing both sides by 3  3y3=363  y = 12  Therefore, the father's age is 4x = 4 \u00d7 12 = 48  Sum of their ages = x + y = 48 + 12 = 60","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>13","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Given that y = px + q and y = 5 ; when x = 3 while y = 4, when x = 2, find the values of p and q","images":[],"options":{"A":"p = 1, q = 3","B":"p = 1 and q = 2","C":"p = -2, q = 3","D":"p = 3, q = -2"},"answer":"B","explanation":"y = px + q  substituting values for x, and y  1st case,  when y = 5, x = 3  Therefore, substituting  5 = 3p + q .................. eqn 1    2nd case,  when y = 4, x = 2  substituting   4 = 2p + q ................. eqn 2  Using Elimination method, eqn 2 ---- eqn 1  4 = 2p + q --------- eqn 2  5 = 3p + q ---------- eqn 1  substracting both equations we have,    -1 = -p  dividing both sides by -1  -1-1=-p-p  Therefore p = 1,    substituting p as 1 in eqn 1, we have  5 = 3p + q  5 = 3(1) + q  5 = 3 + q  q = 5 - 3 = 2    Therefore p = 1 and Q = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>14","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"Evaluatex2+x-22x2+x-3when x = -1","images":[],"options":{"A":"-2","B":"-1","C":"-12","D":"1"},"answer":"D","explanation":"substituting x for -1  X2 + X - 22X2 + X - 3  this gives, (-1)2 + (-1) - 22(-1)2 + (-1) - 3  which gives,  1 - 1 - 22 x 1 - 1 - 3=-2-2=1","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>15","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"factorise 6x2 + 7x - 20","images":[],"options":{"A":"(6x-5)(x+4)","B":"2(3x-5)(x+2)","C":"(3x+4)(2x-5)","D":"(3x-4)(2x+5)"},"answer":"D","explanation":"6x2 + 7x - 20  6x2 + 7x - 20  expanding   6x2 + 15x - 8x - 20  3x(2x + 5) - 4(2x + 5)  (3x - 4)(2x + 5)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>16","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"simplify2x-13-x+32","images":[],"options":{"A":"x+76","B":"x+86","C":"x-116","D":"x-46"},"answer":"C","explanation":"2x-13-x+32  the l.c.m of the denominators is 6  2(2x-1)-3(x+3)6  opening up brackets  4x - 2 - 3x - 96  collecting like terms  4x - 3x - 2 - 96  x-116","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>17","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"y-322y-13  which of the following is true","images":[],"options":{"A":"y >7","B":"y","C":"y >-7","D":"y"},"answer":"C","explanation":"y-322y-13  the LCM of the denominators is 6  multiplying through by the L.C.M  6\u00d7y - 322y - 13x6  this give,  3(y - 3)  opening up brackets  3y - 9  subtracting -3y from both sides  3y - 9 - 3y    This gives, -9  adding two, to both sides   -9 + 2  -7  y > -7","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>18","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"if4m+3n4m-3n=52,findtheratiom:n","images":[],"options":{"A":"7 : 4","B":"8 : 5","C":"-1 : -4","D":"1 : 2"},"answer":"A","explanation":"4m + 3n4m - 3n=52  cross multiply  2(4m + 3n) = 5(4m - 3n)  8m + 6n = 20m - 15n  collecting like terms  6n + 15n = 20m - 8m  21n = 12m  Therefore,  Mn=2122  M : n = 21 : 12    Simplifying  M : n = 7 : 4","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>19","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : POSITIVE AND NEGATIVE INTEGERS, RATIONAL NUMBERS","question":"The number line represent","images":["data:image/png;base64,"],"options":{"A":"0>x\u2265-7","B":"-7 \u2264 x \u2264 1","C":"-7","D":"-7"},"answer":"C","explanation":"The inequality in the diagram represents   -7","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2001>20","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"if 2x2 + kx -14 = (x+2)(2x-7), find the value of k","images":[],"options":{"A":"-3","B":"5","C":"9","D":"11"},"answer":"A","explanation":"2x2 + Kx - 14 = (x + 2)(2x - 7)  expanding the R.H.S,  (x + 2)(2x - 7)  2x2 - 7x + 4x - 14  2x2 - 3x - 14  Therefore,  2x2 + Kx - 14 = 2x2 - 3x - 14  comparing  k = -3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>21","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Which of the following is not a quadratic expression","images":[],"options":{"A":"y = 2x2 - 5x","B":"y = x (x-5 )","C":"y = x2 - 5","D":"y = 5(x-1)"},"answer":"D","explanation":"A quadratic equation has it highest power of X as 2 and not less  Therefore, y = 5(x - 1) does not, it is not a quadratic equation.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2001>22","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph of the curve y  = 2x2 - 5x - 1 and a straight line PQ were drawn to solve the equation  2x2 - 5x + 2 = 0. what is the equation of the line PQ","images":[],"options":{"A":"y = -1","B":"y = 1","C":"y = 3","D":"y = -3"},"answer":"D","explanation":"y = 2x2 - 5x - 1, y = 2x2 - 5x + 2  solving this equations,  equating both equations,  2x2 - 5x - 1 - y = 2x2 - 5x + 2  y = 2x2 - 5x - 1 - 2x2 + 5x - 2  y = -3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>23","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"subtract (-y +3x + 5z) from (4y - x - 2z)","images":[],"options":{"A":"5y - 4x - 7z","B":"3y + 2x + 3z","C":"c -5y + 4x + 7z","D":"2x - 5y + 3z"},"answer":"A","explanation":"subtracting,  4y - x - 2z - (-y + 3x + 5z)  opening up bracket  4y - x - 2z + y - 3x - 5z  5y - 4x - 6z - z  5y - 4x - 7z","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>24","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"if y  \u221d  1\u221ax  and x = 16 when y = 2, find x when y = 24","images":[],"options":{"A":"19","B":"16","C":"13","D":"23"},"answer":"A","explanation":"y\u03b11&radic;x&nbsp;  therefore,  y=k&radic;x&nbsp;  substituting values  2=k&radic;16&nbsp;  k = 8  y=8&radic;x&nbsp;  If y = 24  Therefore,  24=8&radic;x&nbsp;  &radic;x&nbsp;=824=13  Addx=(13)2  x=19.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>25","subject":"Mathematics","year":"2001","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"If 2x: (x+1) = 3:2 what is the value of x?","images":[],"options":{"A":"1/2","B":"1","C":"2","D":"3"},"answer":"D","explanation":"This is a ratio  2x : (x + 1) = 3 : 2  2xx + 1=32  cross-multiplying,  2(2x) = 3(x + 1)  opening up brackets,  4x = 3x + 3  4x - 3x = 3  x = 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>26","subject":"Mathematics","year":"2001","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"The bearing is S40\u2218E is the same as","images":[],"options":{"A":"040\u2218","B":"050\u2218","C":"130\u2218","D":"140\u2218"},"answer":"D","explanation":"Bearing = S40\u00b0E      Bearing = 180 - 40 = 140\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2001>27","subject":"Mathematics","year":"2001","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Given that sin P = 5/13, where p is an acute, find the value of cos P-tan P","images":[],"options":{"A":"79156","B":"85156","C":"713","D":"813"},"answer":"A","explanation":"If sin P = 5/13    Using pythagoras theorem,  BC2 = 132 - 52  BC2 = 169 - 25   BC = &radic;144&nbsp;  BC = 12  CosP-tanP=1213-512  =79156","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>28","subject":"Mathematics","year":"2001","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"Three observation post P, Q and R are such that Q is due east of p and R is due north of Q. if |PQ| = 5km and |PR| = 10km, find |QR|","images":[],"options":{"A":"5.0km","B":"7.5km","C":"7.6km","D":"8.7km"},"answer":"D","explanation":"(PR)2 = (PQ)2 + (QR)2  102 = 52 + (QR)2  (QR)2 = 100 - 25  QR = &radic;75&nbsp;  QR = 8.660km  QR = 8.7km","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>29","subject":"Mathematics","year":"2001","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Express 25\u221845' in decimal (hint 1\u2218 = 60')","images":[],"options":{"A":"25.75\u2218","B":"25.55\u2218","C":"25.45\u2218","D":"25.15\u2218"},"answer":"A","explanation":"25\u00b045'  This gives,  25\u00b0+4560  \u21d2 25\u00b0 + 0.75\u00b0 = 25.75\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>30","subject":"Mathematics","year":"2001","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A box contains 5 red , 3 green and 4 blue balls .A boy is allowed to take away two balls from the box, use this information to answer question    what is the probability that the  two balls are red","images":[],"options":{"A":"5/33","B":"5/36","C":"103/132","D":"31/36"},"answer":"A","explanation":"Total number of balls = 5 + 3 + 4   \u21d2 12 balls  P(firstballred)=512  P(secondballred)=411  P(Bothballsred)=512x411=533","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>31","subject":"Mathematics","year":"2001","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A box contains 5 red , 3 green and 4 blue balls .A boy is allowed to take away two balls from the box, use this information to answer question   what is the probability that is green and the other blue","images":[],"options":{"A":"2/11","B":"5/12","C":"8/12","D":"7/11"},"answer":"A","explanation":"Pr (one green, one blue) = Pr (1st green, 2nd blue) + Pr (1st blue, 2nd green)  \u21d2(312x411)+(412x311)  111+111=211","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>32","subject":"Mathematics","year":"2001","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"if the probability that an event will occur is p and the probability that it will not occur is q, which of the following is true?","images":[],"options":{"A":"p - q = 1","B":"q-p = 0","C":"p+q = 1","D":"p + q = 0"},"answer":"C","explanation":"Pr (An even will occur) = P  Pr (the event will not occur) = q    Therefore,  P + q = 1","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2001>33","subject":"Mathematics","year":"2001","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The histogram shows the distribution of a group of student according to their ages. use the information to answer questions  vertical-axis: 2cm rep 5 students  horizontal-axis : 2cm rep 5 years      what is the range of their ages?","images":["data:image/png;base64,"],"options":{"A":"14 years","B":"20 years","C":"30.5 years","D":"31 years"},"answer":"B","explanation":"Range = Highest age - Lowest age  \u21d2 30.5 - 10.5 = 20 yrs","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>34","subject":"Mathematics","year":"2001","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The histogram shows the distribution of a group of student according to their ages. use the information to answer questions  vertical-axis: 2cm rep 5 students  horizontal-axis : 2cm rep 5 years    What is the mode?","images":["data:image/png;base64,"],"options":{"A":"22.5 years","B":"23.0 years","C":"24.0 years","D":"24.5 years"},"answer":"C","explanation":"Mode is the point of intersection of the two bars crossing at the modal class, and traced down.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>35","subject":"Mathematics","year":"2001","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The histogram shows the distribution of a group of student according to their ages. use the information to answer questions  vertical-axis: 2cm rep 5 students  horizontal-axis : 2cm rep 5 years    How many student are there in the group?","images":["data:image/png;base64,"],"options":{"A":"25","B":"30","C":"52","D":"55"},"answer":"C","explanation":"Total number of students in the group is the summation of frequency  6 + 10 + 20 + 16 = 52 students","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>36","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"Which of the following is not the size of an exterior angle of a regular polygon ?","images":[],"options":{"A":"15\u2218","B":"18\u2218","C":"20\u2218","D":"21\u2218"},"answer":"D","explanation":"The sum of all the exteriors angles of a polygon = 360\u00b0  For this to be accomplished,  when exterior angle divides 360 there should be no remember,  21\u00b0 is not factor.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>37","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the diagram , PQR is a triangle |PQ| = |PR| , |PS| = |SQ| and PR\u0302S = 50\u2218 what is the size of \u2220PSQ","images":["data:image/png;base64,"],"options":{"A":"75\u2218","B":"80\u2218","C":"85\u2218","D":"95\u2218"},"answer":"B","explanation":"PQR is isosceles  Q = 50\u00b0  This is the base angle,  since it is isosceles,  50\u00b0 + 50\u00b0 +   PQR is an isosceles triangle.   50 + 50 x = 180  x = 180 - 100  x = 80\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>38","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"PQRS is a rhombus of side 16cm. the diagonal |QS|  = 20 cm . calculate , correct to the nearest degree \u2220PQR","images":[],"options":{"A":"51\u2218","B":"64\u2218","C":"77\u2218","D":"103\u2218"},"answer":"D","explanation":"cos\u03b1=1016=0.625  \u03b1 = cos-1(0.625)  \u21d2 51.3\u00b0   \u21d2 2(51.3\u00b0)  \u21d2 102.6\u00b0  \u2248 103\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>39","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, PQ is a diameter of the circle and \u2220PRS = 58\u2218 find \u2220STQ","images":["data:image/png;base64,"],"options":{"A":"29\u2218","B":"32\u2218","C":"42\u2218","D":"53\u2218"},"answer":"B","explanation":"Join y QR,  Therefore, (angles in a semi circle)   58 + x = 90\u00b0  x = 90 - 58  x = 32\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>40","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Which of the following pairs of triangles is similar","images":["data:image/png;base64,"],"options":{"A":"II only","B":"III only","C":"i and III only","D":"II and III only"},"answer":"B","explanation":"Similar triangles have similar ratio,   The triangles in III have similar ratio of 1 : 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>41","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram , O is the center of the circle. Reflex angle XOY = 210\u2218 and the length of the minor arc is 5.5m. find correct to the nearest meter, length of the major arc XY.","images":["data:image/png;base64,"],"options":{"A":"8m","B":"9m","C":"10m","D":"13m"},"answer":"A","explanation":"Length of Minor arc = 5.5m  angle of minor arc = 360 - 210 = 150\u00b0  Using ratios,  5.5150=x210  x=5.5 x 210150=8m","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>42","subject":"Mathematics","year":"2001","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A right pyramid is on a square base of side 4cm. the slanting side of the pyramid is 2\u221a3. calculate the volume of the pyramid","images":[],"options":{"A":"5 1/3cm3","B":"10 2/3cm3","C":"16cm3","D":"32cm3"},"answer":"B","explanation":"diagonal = 4&radic;2&nbsp;  Base = square of side 4  height = h  using pythagoras theorem  x2 + (2(&radic;2&nbsp;))2 = (2&radic;3&nbsp;)2  x2 = 4  x = 2  Volume=13Ah  =13(16\u00d72)  =1023cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>43","subject":"Mathematics","year":"2001","type":"Objective","topic":"MENSURATION : AREAS","question":"the height of a right circular cone is 4cm. the radius of its base is 3cm. find its curve surface area","images":[],"options":{"A":"9\u22bccm2","B":"15\u22bccm2","C":"16\u22bccm2","D":"32\u22bccm2"},"answer":"B","explanation":"h = 4cm, r = 3cm  curve surface area = \u03c0rL  L = slant height  L2 = 42 + 32  L2 = 16 + 9  L2 = 25  L = &radic;25&nbsp; = 5    Curved surface = \u03c0(3)(5) = 15\u03c0cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>44","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"A chord of length 30cm is 8cm away from the circle what is the radius of the circle?","images":[],"options":{"A":"16cm","B":"17cm","C":"18cm","D":"20cm"},"answer":"B","explanation":"Using pythagoras theorem  r2 = 152 + 82  r2 = 225 + 64  r2 = 289  r = &radic;289&nbsp;  r = 17cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>45","subject":"Mathematics","year":"2001","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"A sector of a circle radius 14cm subtends an angle of 135\u2218 at the center of the circle. what is the perimeter of the sector?","images":[],"options":{"A":"47cm","B":"61cm","C":"88cm","D":"231cm"},"answer":"B","explanation":"Perimeterofsector=\u03b8360\u00d72\u03c0r+2r  substituting values in  135360\u00d72\u03c0r+2r  33 + 28 = 61cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>46","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram,MN||PQ,|LM| = 3cm and |LP| = 4cm. if the area of \u2206LMN is 18cm2. find the area of quadrilateral MPQN","images":["data:image/png;base64,"],"options":{"A":"3cm2","B":"6cm2","C":"14cm2","D":"24cm2"},"answer":"C","explanation":"LMLP=34  Area of LMNArea of LPQ=3242  AreaofLPQ=169\u00d718=32cm2  \u2234AreaofquadrilateralMPQN=32\u201318=14cm2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2001>47","subject":"Mathematics","year":"2001","type":"Objective","topic":"MENSURATION : AREAS","question":"The diagram shows a trianglar prism of length 7cm. the right-angled triangle PQR is a cross-sector of the prism |PR| = 5cm and |RQ| = 3cm. use the information to answer question    What is the area of the cross-section?","images":["data:image/png;base64,"],"options":{"A":"4cm2","B":"6cm2","C":"15cm2","D":"20cm2"},"answer":"B","explanation":"RP2 = QR2 + QR2 in \u2206RPQ  52 = QP2 + 32  QP2 = 25 - 9  QP = \u221a16  QP = 4  Area = 1/2 x base  x height    = 1/2 x 3 x 4    = 6cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>48","subject":"Mathematics","year":"2001","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The diagram shows a trianglar prism of length 7cm. the right-angled triangle PQR is a cross-sector of the prism |PR| = 5cm and |RQ| = 3cm. use the information to answer question  What is the volume of the prism?","images":["data:image/png;base64,"],"options":{"A":"28cm2","B":"42cm2","C":"70cm2","D":"20cm2"},"answer":"B","explanation":"Volume of prism = Cross-sectional area \u00d7 Length  V = 6cm2 \u00d7 7cm  V = 42cm3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>49","subject":"Mathematics","year":"2001","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A solid cylinder of radius 7cm is 10cm long. find is total surface area","images":[],"options":{"A":"70\u03c0cm2","B":"189\u03c0cm2","C":"210\u03c0cm2","D":"238\u03c0cm2"},"answer":"D","explanation":"Total surface area = 2\u03c0r2 + 2\u03c0rh  TSA = 2\u03c0(7)2 + 2\u03c0(7)10  TSA = 98\u03c0 + 140\u03c0  TSA = 238\u03c0cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2001>50","subject":"Mathematics","year":"2001","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"PQRS is a trapezium in which |PS| = 9cm, |QR| = 15cm, |PQ| = 2\u221a3, \u2220PQR = 90\u2218 and \u2220QRS = 30\u2218. calculate the area of the trapezium","images":["data:image/png;base64,"],"options":{"A":"24\u221a3 cm2","B":"36\u221a3cm2","C":"42\u221a3cm2","D":"72\u221a3cm2"},"answer":"A","explanation":"From the diagram TR = 15 - 9 = 6cm  tan30\u00b0=ST6  Therefore,  6tan30\u00b0 = ST = 2&radic;3&nbsp;  Areaoftrapezium=12(a+b)h  =12(9+15)2&radic;3&nbsp; = 24&radic;3&nbsp;cm2","marks":"1","difficulty":"3"}];